#include <bits/stdc++.h>
using namespace std;
struct stu{
    int num,c,m,e,a;
}a[303];
bool cmp(stu a,stu b){
    if(a.a==b.a){
        if(a.c==b.c){
            return a.num<b.num;
        }
        return a.c>b.c;
    }
    return a.a>b.a;
}
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i].c>>a[i].m>>a[i].e;
        a[i].num=i;a[i].a=a[i].c+a[i].m+a[i].e;
    }
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=5;i++)printf("%d %d\n",a[i].num,a[i].a);
    return 0;
}
